const W=Math.min(innerWidth,480),H=innerHeight,TILE=48;class Sce extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x10141f);this.gx=60;this.gy=80;this.p={x:1,y:1};this.box={x:3,y:3};this.goal={x:6,y:5};this.portA={x:2,y:5};this.portB={x:7,y:2};this.c=this.input.keyboard.createCursorKeys();this.r=this.input.keyboard.addKey('R');this.draw();}mv(dx,dy){const nx=this.p.x+dx,ny=this.p.y+dy;if(nx<0||ny<0||nx>8||ny>6)return;if(nx===this.box.x&&ny===this.box.y){const bx=this.box.x+dx,by=this.box.y+dy;if(bx<0||by<0||bx>8||by>6)return;this.box={x:bx,y:by};}this.p={x:nx,y:ny};if(this.p.x===this.portA.x&&this.p.y===this.portA.y)this.p={...this.portB};if(this.p.x===this.portB.x&&this.p.y===this.portB.y)this.p={...this.portA};if(this.box.x===this.goal.x&&this.box.y===this.goal.y)this.end=true;this.draw();}draw(){if(this.g)this.g.clear();else this.g=this.add.graphics();for(let y=0;y<=6;y++)for(let x=0;x<=8;x++)this.g.lineStyle(1,0x334).strokeRect(this.gx+x*TILE,this.gy+y*TILE,TILE,TILE);const rect=(o,c)=>this.g.fillStyle(c).fillRect(this.gx+o.x*TILE+8,this.gy+o.y*TILE+8,TILE-16,TILE-16);rect(this.goal,0x22c55e);rect(this.portA,0x60a5fa);rect(this.portB,0xa78bfa);rect(this.box,0xf59e0b);rect(this.p,0x86efac);if(this.end)this.add.text(W/2,40,'CLEAR R').setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();if(this.end)return;if(Phaser.Input.Keyboard.JustDown(this.c.left))this.mv(-1,0);if(Phaser.Input.Keyboard.JustDown(this.c.right))this.mv(1,0);if(Phaser.Input.Keyboard.JustDown(this.c.up))this.mv(0,-1);if(Phaser.Input.Keyboard.JustDown(this.c.down))this.mv(0,1);}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,scene:[Sce]});
